e": ["npm run lint", "npm run typecheck", "npm run test"], "do_not_change": ["src/features/ledger/lib/amount.ts", "src/lib/money/*", "ingest.ts", "currency-string parsing", "persistence/schema"], "delivery": "gh pr create against main; emit dev-clone.pr.created + implementation.completed; automerge disabled"}], "effort_estimate": {"tasks": 1, "story_points": 2}, "future_work": ["route-level currency-symbol/$-string parsing", "wire ingest.ts to live SMS/OCR/Plaid adapters", "integer-cents persistence migration (persistence/Cloud SQL ADR)"]}}}

